While NexusHV doesn't have a native Terraform provider yet, you can use the libvirt Terraform provider for KVM management and NexusHV's API for monitoring and operations.

Setup Terraform with libvirt provider:
  terraform {
    required_providers {
      libvirt = {
        source = "dmacvicar/libvirt"
        version = "~> 0.7"
      }
    }
  }

  provider "libvirt" {
    uri = "qemu:///system"
  }

  # Create a VM
  resource "libvirt_domain" "web_server" {
    name   = "web-server-01"
    memory = "8192"
    vcpu   = 4

    disk {
      volume_id = libvirt_volume.web_disk.id
    }

    network_interface {
      network_name = "default"
    }

    console {
      type        = "pty"
      target_port = "0"
      target_type = "serial"
    }
  }

  resource "libvirt_volume" "web_disk" {
    name   = "web-server-01.qcow2"
    pool   = "default"
    format = "qcow2"
    size   = 107374182400  # 100GB
  }

Use NexusHV API via Terraform HTTP provider:
  # Register the VM with NexusHV monitoring:
  resource "http" "register_vm" {
    url    = "http://localhost:8080/api/snapshot-policies"
    method = "POST"
    request_headers = {
      Content-Type = "application/json"
    }
    request_body = jsonencode({
      vm_name        = "web-server-01"
      interval_hours = 24
      max_snapshots  = 7
    })
    depends_on = [libvirt_domain.web_server]
  }

Workflow:
  1. Terraform creates VMs via libvirt provider
  2. NexusHV API auto-detects new VMs (live mode)
  3. Terraform sets NexusHV policies via HTTP provider
  4. NexusHV handles monitoring, alerting, and AI analysis

Nginx reverse proxy adds TLS termination, caching, load balancing, and additional security to NexusHV.

nginx configuration:
  # /etc/nginx/sites-available/nexushv
  upstream nexushv_api {
    server 127.0.0.1:8080;
  }

  server {
    listen 443 ssl http2;
    server_name nexushv.example.com;

    ssl_certificate /etc/letsencrypt/live/nexushv.example.com/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/nexushv.example.com/privkey.pem;
    ssl_protocols TLSv1.2 TLSv1.3;
    ssl_ciphers HIGH:!aNULL:!MD5;

    # Security headers
    add_header X-Frame-Options DENY;
    add_header X-Content-Type-Options nosniff;
    add_header X-XSS-Protection "1; mode=block";
    add_header Strict-Transport-Security "max-age=31536000";

    # API proxy
    location /api/ {
      proxy_pass http://nexushv_api;
      proxy_set_header Host $host;
      proxy_set_header X-Real-IP $remote_addr;
      proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
      proxy_set_header X-Forwarded-Proto $scheme;
    }

    # WebSocket proxy
    location /ws/ {
      proxy_pass http://nexushv_api;
      proxy_http_version 1.1;
      proxy_set_header Upgrade $http_upgrade;
      proxy_set_header Connection "upgrade";
      proxy_set_header Host $host;
      proxy_read_timeout 86400;  # 24h for WebSocket
    }

    # Prometheus metrics (restrict to monitoring network)
    location /metrics {
      allow 10.0.0.0/8;
      deny all;
      proxy_pass http://nexushv_api;
    }

    # Frontend static files
    location / {
      proxy_pass http://nexushv_api;
    }
  }

  # Redirect HTTP to HTTPS
  server {
    listen 80;
    server_name nexushv.example.com;
    return 301 https://$server_name$request_uri;
  }

Enable:
  ln -s /etc/nginx/sites-available/nexushv /etc/nginx/sites-enabled/
  nginx -t && systemctl reload nginx

Optional: Rate limiting at nginx level:
  limit_req_zone $binary_remote_addr zone=api:10m rate=50r/s;
  location /api/ {
    limit_req zone=api burst=20;
    proxy_pass http://nexushv_api;
  }

NexusHV provides three WebSocket endpoints for real-time data streaming.

1. Metrics Stream (/ws/metrics):
  Sends host and VM metrics every 2 seconds.

  const ws = new WebSocket('ws://localhost:8080/ws/metrics');
  ws.onmessage = (event) => {
    const d = JSON.parse(event.data);
    console.log(`CPU: ${d.host_cpu}%, RAM: ${d.host_ram}%`);
    d.vms.forEach(vm => {
      console.log(`  ${vm.name}: CPU ${vm.cpu_pct}%`);
    });
  };

  Payload fields:
    ts, host_cpu, host_cpu_per_core, host_ram, host_ram_used_gb,
    host_ram_total_gb, host_disk_pct, host_net_rx, host_net_tx,
    load_avg, vms[].name/cpu_pct/ram_pct/state/disk_io/net_io

2. Event Stream (/ws/events):
  Pushes alerts, VM state changes, HA events in real-time.

  const ws = new WebSocket('ws://localhost:8080/ws/events');
  ws.onmessage = (event) => {
    const d = JSON.parse(event.data);
    if (d.type === 'alert') {
      showNotification(d.data.title);
    }
  };

  Event types: alert, vm_action, ha_event, keepalive

3. AI Stream (/ws/ai/stream):
  Token-by-token AI response streaming.

  const ws = new WebSocket('ws://localhost:8080/ws/ai/stream');
  ws.onopen = () => {
    ws.send(JSON.stringify({message: 'Analyze my cluster'}));
  };
  ws.onmessage = (event) => {
    const d = JSON.parse(event.data);
    if (d.done) { console.log('Complete'); }
    else { process.stdout.write(d.token); }
  };

All WebSocket connections:
  - Auto-reconnect on disconnect
  - JSON format for all messages
  - No authentication required (same as GET endpoints)
  - Not rate-limited after handshake

NexusHV's REST API enables automated VM lifecycle management in CI/CD pipelines.

GitHub Actions example:
  name: VM-based Integration Tests
  on: push
  jobs:
    test:
      runs-on: self-hosted  # Host with NexusHV
      steps:
        - name: Create test VM
          run: |
            TOKEN=$(curl -sf -X POST http://nexushv:8080/api/auth/login \
              -H 'Content-Type: application/json' \
              -d '{"username":"ci","password":"$CI_PASSWORD"}' | jq -r .token)

            curl -sf -X POST http://nexushv:8080/api/vms/template-test/clone \
              -H "Authorization: Bearer $TOKEN" \
              -H 'Content-Type: application/json' \
              -d '{"new_name":"ci-test-$GITHUB_RUN_ID","full_clone":false}'

            curl -sf -X POST http://nexushv:8080/api/vms/ci-test-$GITHUB_RUN_ID/action \
              -H "Authorization: Bearer $TOKEN" \
              -d '{"action":"start"}'

            sleep 30  # Wait for VM to boot

        - name: Run tests
          run: |
            # SSH into VM and run tests
            ssh ci@$VM_IP 'cd /app && make test'

        - name: Cleanup
          if: always()
          run: |
            curl -sf -X DELETE http://nexushv:8080/api/vms/ci-test-$GITHUB_RUN_ID \
              -H "Authorization: Bearer $TOKEN"

Jenkins pipeline:
  pipeline {
    agent any
    stages {
      stage('Create VM') {
        steps {
          sh 'curl -X POST http://nexushv:8080/api/vms/template/clone -d ...'
        }
      }
      stage('Test') {
        steps {
          sh 'ssh ci@vm make test'
        }
      }
    }
    post {
      always {
        sh 'curl -X DELETE http://nexushv:8080/api/vms/ci-vm-$BUILD_ID'
      }
    }
  }

Best practices:
  - Use linked clones (instant creation)
  - Clean up VMs after every run
  - Use power schedules to stop forgotten CI VMs
  - Monitor with: curl http://localhost:8080/api/vms?search=ci

Here's a complete Python client library for NexusHV.

import httpx
import json

class NexusHVClient:
    def __init__(self, url='http://localhost:8080', username='admin', password='admin'):
        self.url = url
        self.client = httpx.Client(timeout=30)
        self.token = self._login(username, password)
        self.headers = {'Authorization': f'Bearer {self.token}'}

    def _login(self, username, password):
        r = self.client.post(f'{self.url}/api/auth/login',
            json={'username': username, 'password': password})
        return r.json()['token']

    def list_vms(self, state=None, search=None):
        params = {}
        if state: params['state'] = state
        if search: params['search'] = search
        return self.client.get(f'{self.url}/api/vms', params=params).json()

    def get_vm(self, name):
        return self.client.get(f'{self.url}/api/vms/{name}').json()

    def create_vm(self, name, cpu=2, ram_gb=4, disk_gb=50):
        return self.client.post(f'{self.url}/api/vms',
            headers=self.headers,
            json={'name': name, 'cpu': cpu, 'ram_gb': ram_gb, 'disk_gb': disk_gb}).json()

    def vm_action(self, name, action):
        return self.client.post(f'{self.url}/api/vms/{name}/action',
            headers=self.headers, json={'action': action}).json()

    def clone_vm(self, name, new_name, full=True):
        return self.client.post(f'{self.url}/api/vms/{name}/clone',
            headers=self.headers,
            json={'new_name': new_name, 'full_clone': full}).json()

    def ai_chat(self, message):
        return self.client.post(f'{self.url}/api/ai/chat',
            json={'message': message}).json()['response']

    def dashboard(self):
        return self.client.get(f'{self.url}/api/dashboard/overview').json()

    def health(self):
        return self.client.get(f'{self.url}/health').json()

# Usage:
nx = NexusHVClient()
print(nx.health())
print(nx.list_vms(state='poweredOn'))
print(nx.ai_chat('Analyze my cluster performance'))

NexusHV's API enables automated infrastructure testing with pytest.

import pytest
import httpx
import time

NEXUS_URL = 'http://localhost:8080'
TOKEN = None

@pytest.fixture(scope='session', autouse=True)
def auth():
    global TOKEN
    r = httpx.post(f'{NEXUS_URL}/api/auth/login',
        json={'username': 'admin', 'password': 'admin'})
    TOKEN = r.json()['token']

def api(method, path, **kwargs):
    headers = {'Authorization': f'Bearer {TOKEN}'}
    return httpx.request(method, f'{NEXUS_URL}{path}', headers=headers, **kwargs)

class TestVMLifecycle:
    VM_NAME = 'pytest-test-vm'

    def test_create_vm(self):
        r = api('POST', '/api/vms', json={
            'name': self.VM_NAME, 'cpu': 2, 'ram_gb': 4, 'disk_gb': 20})
        assert r.status_code == 200

    def test_start_vm(self):
        r = api('POST', f'/api/vms/{self.VM_NAME}/action', json={'action': 'start'})
        assert r.status_code == 200

    def test_vm_is_running(self):
        r = api('GET', f'/api/vms/{self.VM_NAME}')
        assert r.json()['state'] == 'poweredOn'

    def test_create_snapshot(self):
        r = api('POST', f'/api/vms/{self.VM_NAME}/snapshots',
            json={'name': 'test-snap', 'description': 'pytest snapshot'})
        assert r.status_code == 200

    def test_clone_vm(self):
        r = api('POST', f'/api/vms/{self.VM_NAME}/clone',
            json={'new_name': f'{self.VM_NAME}-clone', 'full_clone': False})
        assert r.status_code == 200
        api('DELETE', f'/api/vms/{self.VM_NAME}-clone')

    def test_stop_vm(self):
        r = api('POST', f'/api/vms/{self.VM_NAME}/action', json={'action': 'stop'})
        assert r.status_code == 200

    def test_delete_vm(self):
        r = api('DELETE', f'/api/vms/{self.VM_NAME}')
        assert r.status_code == 200

class TestClusterHealth:
    def test_health(self):
        r = httpx.get(f'{NEXUS_URL}/health')
        assert r.json()['status'] == 'ok'

    def test_diagnostics(self):
        r = httpx.get(f'{NEXUS_URL}/api/diagnostics')
        assert r.json()['overall'] in ('healthy', 'degraded')

    def test_security_posture(self):
        r = httpx.get(f'{NEXUS_URL}/api/security/posture')
        assert r.json()['score'] >= 0

# Run: pytest test_infra.py -v
